import{_ as o,o as t,c as i,a5 as r}from"./chunks/framework.B5tqjWbr.js";const h=JSON.parse('{"title":"教程 0004：离散比例积分控制器（discrete proportional-integral controller / discrete PI）最小闭环","description":"","frontmatter":{"title":"教程 0004：离散比例积分控制器（discrete proportional-integral controller / discrete PI）最小闭环","date":"2026-07-01T00:00:00.000Z","section":"电源控制","chapter":"01-Lessons","category":"电源控制","tags":["imported"],"source":"power","sourcePath":"0004-discrete-pi-boost.html","status":"learning","visibility":"public","summary":"Imported from 0004-discrete-pi-boost.html","chapterTitle":"电源课程","chapterOrder":10},"headers":[],"relativePath":"content/power/lessons/0004-discrete-pi-boost.md","filePath":"content/power/lessons/0004-discrete-pi-boost.md","lastUpdated":1782999393000}'),p={name:"content/power/lessons/0004-discrete-pi-boost.md"};function l(a,e,n,s,c,d){return t(),i("div",null,[...e[0]||(e[0]=[r(`<h1 id="教程-0004-离散比例积分控制器-discrete-proportional-integral-controller-discrete-pi-最小闭环" tabindex="-1">教程 0004：离散比例积分控制器（discrete proportional-integral controller / discrete PI）最小闭环 <a class="header-anchor" href="#教程-0004-离散比例积分控制器-discrete-proportional-integral-controller-discrete-pi-最小闭环" aria-label="Permalink to &quot;教程 0004：离散比例积分控制器（discrete proportional-integral controller / discrete PI）最小闭环&quot;">​</a></h1><p>中文主讲。一个概念：用 Boost 电压闭环看懂控制中断里最常见的一段逻辑：采样、算误差、控制器更新、限幅、输出占空比。</p><pre><code>本页学习顺序
</code></pre><ul><li><p>理解离散比例积分控制器是什么。</p></li><li><p>把比例项、积分项、限幅和占空比命令连起来。</p></li><li><p>写出位置式离散比例积分控制器的基本公式。</p></li><li><p>运行一个仿真任务，观察闭环误差和占空比变化。</p></li><li><p>把仿真波形转换成 C 工程代码阅读问题。</p></li></ul><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>离散比例积分控制器（discrete proportional-integral controller / discrete PI）是在固定控制周期内，根据误差计算控制输出的闭环控制器。</p><p>在 Boost 电压闭环里，误差通常是参考电压减去输出电压：</p><p>e[k] = Vref - Vout[k]</p><p>控制器输出通常会转换成占空比命令（duty command / D）。</p><pre><code>一句话记忆：比例项负责“现在差多少就推多少”，积分项负责“长期差一点就慢慢补回来”。
</code></pre><h2 id="_2-为什么-ups-需要它" tabindex="-1">2. 为什么 UPS 需要它 <a class="header-anchor" href="#_2-为什么-ups-需要它" aria-label="Permalink to &quot;2. 为什么 UPS 需要它&quot;">​</a></h2><p>不间断电源（uninterruptible power supply / UPS）里大量控制目标都需要闭环。</p><pre><code>直流母线
</code></pre><p>直流母线电压（DC bus voltage）需要稳定，不能随负载大幅漂移。 功率因数校正 功率因数校正（power factor correction / PFC）电流环和电压环常见 PI 结构。 读 C 工程 控制中断服务程序（control interrupt service routine / control ISR）里经常出现误差、积分、限幅和占空比更新。</p><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>比例项（proportional term / P）像“看到误差就立刻推一把”。输出电压低于参考越多，占空比命令就增加越多。</p><p>积分项（integral term / I）像“记账”。如果输出长期偏低，积分会不断累加，让占空比继续上调，直到稳态误差变小。</p><p>占空比不能无限大，所以必须有限幅。积分项也不能无限累加，否则输出饱和后还继续积累，恢复时会很慢，这就是积分饱和（integrator windup）。</p><pre><code>采样
Vout[k]

误差
Vref - Vout

控制器
P + I

限幅
Dmin..Dmax

调制
占空比
</code></pre><p>图 1：最小闭环控制流。真实工程还会加入滤波、前馈、保护、状态机和故障处理。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>位置式离散比例积分控制器的一种常见写法：</p><p>e[k] = Vref - Vout[k] I[k] = clamp(I[k-1] + Ki * e[k] * Ts, I_min, I_max) u[k] = clamp(Kp * e[k] + I[k], D_min, D_max)</p><p>其中 <code>Ts</code> 是控制周期（control period），<code>Kp</code> 是比例增益（proportional gain），<code>Ki</code> 是积分增益（integral gain），<code>u[k]</code> 在本节中对应占空比命令。</p><pre><code>本节只讲结构。脚本使用教学用平均模型，不是完整开关模型；它用于看懂 PI 代码结构，不用于真实产品参数设计。
</code></pre><h2 id="_5-一个仿真任务" tabindex="-1">5. 一个仿真任务 <a class="header-anchor" href="#_5-一个仿真任务" aria-label="Permalink to &quot;5. 一个仿真任务&quot;">​</a></h2><p>在 PowerShell 中运行：</p><p>cd E:\\gitee_CodeStorage\\学习\\电源 python simulations\\python\\boost_discrete_pi.py</p><p>脚本会自动打开结果图；如果打不开，会打印完整路径。默认结果图路径：<code>simulations/results/boost_discrete_pi.png</code>。图中包含输出电压、参考电压、电压误差、占空比命令和参数框。</p><pre><code>对比实验：改变 PI 参数
python simulations\\python\\boost_discrete_pi.py --kp 0.006 --ki 40 --output simulations\\results\\boost_discrete_pi_slow.png
</code></pre><p>python simulations\\python\\boost_discrete_pi.py --kp 0.020 --ki 120 --output simulations\\results\\boost_discrete_pi_fast.png python simulations\\python\\boost_discrete_pi.py --duty-max 0.45 --output simulations\\results\\boost_discrete_pi_limited.png</p><p>观察：输出电压接近参考的速度、误差是否变小、占空比是否碰到上限。</p><h2 id="_6-仿真观察" tabindex="-1">6. 仿真观察 <a class="header-anchor" href="#_6-仿真观察" aria-label="Permalink to &quot;6. 仿真观察&quot;">​</a></h2><ul><li><p>先看第一幅子图：<code>Vout</code> 是否靠近 <code>Vref</code>。</p></li><li><p>再看第二幅子图：误差是否逐渐靠近 0。</p></li><li><p>最后看第三幅子图：占空比是否在上下限之间，是否长时间贴着上限或下限。</p></li><li><p>如果 <code>--duty-max 0.45</code> 后输出达不到参考，说明控制器想继续加占空比，但执行器已经受限。</p></li></ul><h2 id="_7-固件落地" tabindex="-1">7. 固件落地 <a class="header-anchor" href="#_7-固件落地" aria-label="Permalink to &quot;7. 固件落地&quot;">​</a></h2><p>在 C 语言固件中，PI 通常出现在控制 ISR 里。这里的 ADC 和 PWM 已在上一节展开，分别指模数转换器（analog-to-digital converter / ADC）采样和脉宽调制（pulse-width modulation / PWM）：</p><p>读取 ADC -&gt; 标幺化/滤波 -&gt; 计算误差 -&gt; PI 更新 -&gt; 限幅 -&gt; 更新 PWM 占空比</p><p>读代码时要重点看：</p><ul><li><p>误差符号：是 <code>Vref - Vout</code> 还是 <code>Vout - Vref</code>。</p></li><li><p>积分项是否乘了控制周期 <code>Ts</code>。</p></li><li><p>限幅位置：限积分、限输出，还是两者都限。</p></li><li><p>输出饱和时，积分是否还继续累加。</p></li><li><p>占空比更新是当前周期立即生效，还是等下一个 PWM 更新事件。</p></li></ul><h2 id="_8-常见误解" tabindex="-1">8. 常见误解 <a class="header-anchor" href="#_8-常见误解" aria-label="Permalink to &quot;8. 常见误解&quot;">​</a></h2><ul><li><p>**误解：**比例增益越大越快越好。 **纠正：**过大的比例增益会导致振荡、噪声放大或占空比频繁打限。</p></li><li><p>**误解：**积分越大越能消除误差。 **纠正：**积分过大可能导致超调和饱和恢复慢。</p></li><li><p>**误解：**输出限幅就够了，积分不用管。 **纠正：**输出饱和时积分继续累加，会造成 windup，必须考虑积分限幅或抗饱和。</p></li><li><p>**误解：**仿真里调好的参数可以直接放到产品。 **纠正：**真实参数还要考虑采样、延迟、功率级、保护、噪声和硬件限制。</p></li></ul><h2 id="_9-验收标准" tabindex="-1">9. 验收标准 <a class="header-anchor" href="#_9-验收标准" aria-label="Permalink to &quot;9. 验收标准&quot;">​</a></h2><ul><li><p>能解释误差、比例项、积分项、限幅和占空比命令的关系。</p></li><li><p>能写出位置式离散 PI 的基本公式。</p></li><li><p>能在图上指出输出电压、参考电压、误差和占空比。</p></li><li><p>能解释为什么占空比上限会导致输出电压达不到参考。</p></li><li><p>能说出读 C 代码时要检查误差符号、积分限幅和 PWM 更新时刻。</p></li></ul><h2 id="_10-复盘问题" tabindex="-1">10. 复盘问题 <a class="header-anchor" href="#_10-复盘问题" aria-label="Permalink to &quot;10. 复盘问题&quot;">​</a></h2><ul><li><p>打开 <code>simulations/results/boost_discrete_pi.png</code>，最终输出电压和参考电压相差多少？最终占空比是多少？</p></li><li><p>运行 <code>--duty-max 0.45</code> 后，如果输出达不到 96 V，是 PI 算法坏了，还是执行器限幅导致的？</p></li><li><p>如果 C 代码里误差写成 <code>Vout - Vref</code>，但 PI 输出仍直接加到占空比上，会发生什么？</p></li></ul><h2 id="_11-导师问题" tabindex="-1">11. 导师问题 <a class="header-anchor" href="#_11-导师问题" aria-label="Permalink to &quot;11. 导师问题&quot;">​</a></h2><ul><li><p>我用 <code>boost_discrete_pi.py</code> 看到默认参数下最终输出约 96 V，占空比约 0.488。公司代码里的 Boost 或功率因数校正（power factor correction / PFC）电压环 PI 是位置式还是增量式？</p></li><li><p>我在脚本里对占空比和积分项都做了限幅。公司工程里抗积分饱和通常怎么写，是否有统一 PI 模块？</p></li><li><p>如果 ADC 采样值和 PWM 更新之间有一拍延迟，公司代码中会在 PI 参数整定时显式考虑这个延迟吗？</p></li></ul><p>**下一步：**完成这节后，记录默认图的最终输出电压、最终占空比和误差。后续可以继续做 Boost 闭环调参，再过渡到单相 PFC。</p><p>关联：<a href="./0003-pwm-sampling.html">上一节：脉宽调制与采样时刻</a>；源稿：<code>concepts/power-electronics/discrete-pi-boost.md</code>。</p><pre><code>上一节：教程 0003：脉宽调制（pulse-width modulation / PWM）与模数转换器采样（analog-to-digital converter / ADC sampling）
下一节：教程 0005：Boost 控制中断服务程序（control interrupt service routine / control ISR）软件骨架
</code></pre>`,50)])])}const _=o(p,[["render",l]]);export{h as __pageData,_ as default};
